  Object.defineProperty(document, "body", { get: function() { return body; }, configurable: true });
  document.createElement = function(tag, opts) { return document.createElementNS(ns, tag, opts); };

  function injectScript(src, isModule, isAsync) {
    var s = document.createElementNS(ns, "script");
    s.setAttribute("src", src);
    if (isModule) s.setAttribute("type", "module");
    if (isAsync) s.setAttribute("async", "");
    body.appendChild(s);
