    if (extra) for (var k in extra) l.setAttribute(k, extra[k]);
    head.appendChild(l);
  }

  function injectStyle(css) {
    var s = document.createElementNS(ns, "style");
    s.textContent = css;
    head.appendChild(s);
  }

  var mc = document.createElementNS(ns, "meta");
  mc.setAttribute("charset", "UTF-8");
  head.appendChild(mc);
  var mv = document.createElementNS(ns, "meta");
  mv.setAttribute("name", "viewport");
  mv.setAttribute("content", "width=device-width, initial-scale=1.0, viewport-fit=cover");
  head.appendChild(mv);

  // importmap so all bare /path imports resolve to jsdelivr
  var im = document.createElementNS(ns, "script");
  im.setAttribute("type", "importmap");
  im.textContent = JSON.stringify({
