    "var _f=window.fetch;window.fetch=function(u,o){return _f.call(this,_rw(u),o);};" +
    "var _x=XMLHttpRequest.prototype.open;XMLHttpRequest.prototype.open=function(m,u){return _x.call(this,m,_rw(u));};"
  );

  injectScript("https://www.googletagmanager.com/gtag/js?id=G-DQZPCVEF89", false, true);
  injectInlineScript("window.dataLayer=window.dataLayer||[];function gtag(){dataLayer.push(arguments);}gtag('js',new Date());gtag('config','G-DQZPCVEF89');");
  injectLink("preconnect", "https://fonts.googleapis.com", { crossorigin: "" });
  injectLink("preconnect", "https://fonts.gstatic.com", { crossorigin: "" });
  injectLink("stylesheet", "https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap");
  injectStyle("html,body,*{font-family:'Inter',sans-serif;}html,body{background:#11121c;color:#fff;}");
  injectScript(base + "/_astro/index.astro_astro_type_script_index_0_lang.eXFzIz31.js", true, false);
